padraoUsuario.Call('G', 'HAVERSERLECIONADO_CTR', &Context.PesCod, &Context.EmpCod, '', &PadDtaMod) If &Context.PesCod < 0 &auxPesCod = &Context.PesCod*-1 Else &auxPesCod = &Context.PesCod EndIf &PedCod = val(str(Year(&Today))+str(&auxPesCod))*-1 ApagaTemporariaPedidoVenda.Call(&Context.EmpCod, &Context.FilCod, &PedCod, &PedTmpFrpPgtoTip)
do 'GravaPadrao'
If not &CrePagDta.IsEmpty() If &SdtPagamentoDuplicata.Count = 0 msg('Nenhum Registro selecionado!') Else If (&TotDescontada > 0 and &TotNaoDescontada = 0) or (&TotNaoDescontada > 0 and &TotDescontada = 0)
&WebSession.Set('WWDuplicataReceber',&SdtPagamentoDuplicata.Toxml())
RecebimentoDuplicata_JDF.Call(&CreFilPgt, &CrePagDta,'WWDuplicataReceber2') Else msg('Não é permitido baixar duplicatas do status "Descontada" com Duplicatas Normais!') EndiF EndIF Else msg('Data do pagamento não pode ser vazia!') &CrePagDta = &Hoje &CrePagDta.SetFocus() EndIf
