Sub 'InitializeColumnsSelector'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ColumnsSelector = new WWPColumnsSelector() WWP_ColumnsSelector_Add(&ColumnsSelector, !"&CreNovCliRaz", '', !'Nome Cliente', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreDupNro", '', !'Nro', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreDtaEms", '', !'Emis.', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreDtaVct", '', !'Vcto.', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreVlrDup", '', !'Valor', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreVlrSdo", '', !'À Receber', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&CreVlrJur", '', !'Juros', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&CreVlrPgt", '', !'Recebeu?', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&CreTipBxa", '', !'Tipo', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreVenCod", '', !'Vend.', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&AuxPedido", '', !'Origem', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreCod", '', !'Seq.', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreCbrCod", '', !'LC', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"CreFilPgt", '', !'F.', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"&SalvaLinha", '', !'', True, '')
&UserCustomValue = LoadColumnsSelectorState.Udp(!'wwDuplicataReceber2ColumnsSelector') If not(&UserCustomValue.IsEmpty()) &ColumnsSelectorAux.FromXml(&UserCustomValue) WWP_ColumnSelector_UpdateColumns(&ColumnsSelectorAux, &ColumnsSelector) EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
