&CreDupNro1.Visible = False &CreCbrNom1.Visible = False Do Case Case &DynamicFiltersSelector1 = !'CREDUPNRO' &CreDupNro1.Visible = True Case &DynamicFiltersSelector1 = !'CRECBRNOM' &CreCbrNom1.Visible = True EndCase
