Sub 'LoadGridState'
if 1=2
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(&PgmName + !"GridState") = !"" &GridState.FromXml(LoadGridState.Udp(&PgmName + !"GridState")) Else &GridState.FromXml(&Session.Get(&PgmName + !"GridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc Do 'SetDDOSortedStatus'
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"CRECLICOD" &CreCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRECLICODRAZSUGG" &CreCliCodRazSugg.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREFILPGT" &CreFilPgt.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREDTAVCT" &CreDtaVct.FromString(&GridStateFilterValue.Value) &CreDtaVct_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"CRERECPAG" &CreRecPag.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRESTS" &CreSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREVLRSDO" &CreVlrSdo.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREFRPPGTOTIP" &CreFrpPgtoTip.FromString(&GridStateFilterValue.Value) EndCase EndFor Do 'LoadDynFiltersState' If not &GridState.PageSize.Trim().IsEmpty() Grid.Rows = &GridState.PageSize.ToNumeric() EndIf Grid.CurrentPage = &GridState.CurrentPage
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Endif
EndSub
Sub 'LoadDynFiltersState'
if 1=2
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
AddDynamicFilters1.Visible = True RemoveDynamicFilters1.Visible = False AddDynamicFilters2.Visible = True RemoveDynamicFilters2.Visible = False
If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CREDUPNRO' &CreDupNro1.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector1 = !'CRECBRNOM' &CreCbrNom1.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters1' If &GridState.DynamicFilters.Count >= 2 JSDynamicFilters.Caption = !'<script type="text/javascript">$(document).ready(function() {' JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 2, 0);", TableDynamicFilters.InternalName) AddDynamicFilters1.Visible = False RemoveDynamicFilters1.Visible = True &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CREDUPNRO' &CreDupNro2.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector2 = !'CRECBRNOM' &CreCbrNom2.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters2' If &GridState.DynamicFilters.Count >= 3 JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 3, 0);", TableDynamicFilters.InternalName) AddDynamicFilters2.Visible = False RemoveDynamicFilters2.Visible = True &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CREDUPNRO' &CreDupNro3.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector3 = !'CRECBRNOM' &CreCbrNom3.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters3' EndIf JSDynamicFilters.Caption += !'});</script>' EndIf EndIf If &DynamicFiltersRemoving JSDynamicFilters.Caption = '' EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Endif
EndSub
Sub 'SaveGridState'
if 1=2
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.FromXml(&Session.Get(&PgmName + !"GridState"))
// Save grid state in session. &GridState.OrderedBy = &OrderedBy &GridState.OrderedDsc = &OrderedDsc &GridState.FilterValues.Clear() WWP_GridStateAddFilterValue(&GridState, !"CRECLICOD", "", not &CreCliCod.IsEmpty(), 0, &CreCliCod.ToString().Trim(), '') WWP_GridStateAddFilterValue(&GridState, !"CRECLICODRAZSUGG", "", not &CreCliCodRazSugg.IsEmpty(), 0, &CreCliCodRazSugg, '') WWP_GridStateAddFilterValue(&GridState, !"CREFILPGT", "", not &CreFilPgt.IsEmpty(), 0, &CreFilPgt.ToString().Trim(), '') WWP_GridStateAddFilterValue(&GridState, !"CREDTAVCT", "", not (&CreDtaVct.IsEmpty() AND &CreDtaVct_To.IsEmpty()), 0, &CreDtaVct.ToString().Trim(), &CreDtaVct_To.ToString().Trim()) WWP_GridStateAddFilterValue(&GridState, !"CRERECPAG", "", true, 0, &CreRecPag, '') WWP_GridStateAddFilterValue(&GridState, !"CRESTS", "", not &CreSts.IsEmpty(), 0, &CreSts, '') WWP_GridStateAddFilterValue(&GridState, !"CREVLRSDO", "", not &CreVlrSdo.IsEmpty(), 0, &CreVlrSdo.ToString().Trim(), '') WWP_GridStateAddFilterValue(&GridState, !"CREFRPPGTOTIP", "", not &CreFrpPgtoTip.IsEmpty(), 0, &CreFrpPgtoTip, '')
Do 'SaveDynFiltersState'
&GridState.PageSize = str(Grid.Rows) &GridState.CurrentPage = Grid.CurrentPage SaveGridState.Call(&PgmName + !"GridState", &GridState.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
endif
EndSub
Sub 'SaveDynFiltersState'
if 1=2
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.DynamicFilters.Clear() If not &DynamicFiltersIgnoreFirst &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector1 Do Case Case &DynamicFiltersSelector1 = !'CREDUPNRO' AND not &CreDupNro1.IsEmpty() &GridStateDynamicFilter.Value = &CreDupNro1.ToString() Case &DynamicFiltersSelector1 = !'CRECBRNOM' AND not &CreCbrNom1.IsEmpty() &GridStateDynamicFilter.Value = &CreCbrNom1.ToString() EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled2 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector2 Do Case Case &DynamicFiltersSelector2 = !'CREDUPNRO' AND not &CreDupNro2.IsEmpty() &GridStateDynamicFilter.Value = &CreDupNro2.ToString() Case &DynamicFiltersSelector2 = !'CRECBRNOM' AND not &CreCbrNom2.IsEmpty() &GridStateDynamicFilter.Value = &CreCbrNom2.ToString() EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled3 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector3 Do Case Case &DynamicFiltersSelector3 = !'CREDUPNRO' AND not &CreDupNro3.IsEmpty() &GridStateDynamicFilter.Value = &CreDupNro3.ToString() Case &DynamicFiltersSelector3 = !'CRECBRNOM' AND not &CreCbrNom3.IsEmpty() &GridStateDynamicFilter.Value = &CreCbrNom3.ToString() EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Endif
EndSub
Sub 'PrepareTransaction'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&TrnContext = new() &TrnContext.CallerObject = &Pgmname &TrnContext.CallerOnDelete = True &TrnContext.CallerURL = &HTTPRequest.ScriptName + !"?" + &HTTPRequest.QueryString &TrnContext.TransactionName = !"Duplicatas"
&Session.Set(!"TrnContext", &TrnContext.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Event &CreDtaVct.IsValid
If not &CreDtaVct.IsEmpty() and &CreDtaVct_To < &CreDtaVct &CreDtaVct_To = &CreDtaVct EndIf
EndEvent
Event &CreVlrJur.IsValid
if &OldCreVlrJur <> &CreVlrJur if &CreVlrJur < 0 &CreVlrJur = 0 EndIF
If &CreDupSel = True and (&CreVlrJur <> 0 or (&CreVlrPgt > CreVlrSdo)) &CreVlrPgt = CreVlrSdo+&CreVlrJur EndIf
For &SdtpagamentoDuplicataItem in &SdtpagamentoDuplicata If &SdtpagamentoDuplicataItem.CreCod = CreCod &SdtpagamentoDuplicataItem.CreVlrPgt = &CreVlrPgt &SdtpagamentoDuplicataItem.CrePagVlrJur = &CreVlrJur Exit EndIf EndFor
do 'GravaSelecionadas' &OldCreVlrJur = &CreVlrJur &OldCreVlrPgt = &CreVlrPgt Endif
EndEvent
Event &CreVlrPgt.IsValid
if &OldCreVlrPgt <> &CreVlrPgt If &CreVlrPgt > CreVlrSdo and &CreTipBxa = TipoDuplicataBaixa.Total and &CreDupSel = True &CreVlrJur = &CreVlrPgt - CreVlrSdo EndIf If &CreVlrPgt < CreVlrSdo and &CreTipBxa = TipoDuplicataBaixa.Total and &CreDupSel = True &CreVlrDsc = CreVlrSdo-&CrevlrPgt EndIf
For &SdtpagamentoDuplicataItem in &SdtpagamentoDuplicata If &SdtpagamentoDuplicataItem.CreCod = CreCod &SdtpagamentoDuplicataItem.CreVlrPgt = &CreVlrPgt &SdtpagamentoDuplicataItem.CrePagVlrJur = &CreVlrJur &SdtpagamentoDuplicataItem.CrePagVlrDsc = &CreVlrDsc Exit EndIf EndFor
do 'GravaSelecionadas' &OldCreVlrJur = &CreVlrJur &OldCreVlrPgt = &CreVlrPgt Endif
EndEvent
Event &CreTipBxa.IsValid
if &OldCreTipBxa <> &CreTipBxa For &SdtpagamentoDuplicataItem in &SdtpagamentoDuplicata If &SdtpagamentoDuplicataItem.CreCod = CreCod &SdtpagamentoDuplicataItem.CreTipBxa = &CreTipBxa &SdtpagamentoDuplicataItem.CreVlrPgt = &CreVlrPgt If &CreTipBxa = TipoDuplicataBaixa.Parcial &SdtpagamentoDuplicataItem.CrePagVlrDsc = 0 EndIf Exit EndIf EndFor
do 'GravaSelecionadas' &OldCreTipBxa = &CreTipBxa Endif
EndEvent
Event 'Prompt'
4 PromptCliente.Popup(&EmpCod, &CreCliCod)
EndEvent
Event limpar_campo.Click
&SdtPagamentoDuplicata.Clear() do 'GravaSelecionadas' Refresh
EndEvent
Event &IsMostrarJuros.click
if &IsMostrarJuros = true For &SdtPagamentoDuplicataItem in &SdtPagamentoDuplicata &CreVlrJur = 0 &MoraMoeda = 0 CalculaJuros.Call(&Context.EmpCod,&SdtPagamentoDuplicataItem.JurCod, &SdtPagamentoDuplicataItem.CreDtaVct,&CrePagDta, &SdtPagamentoDuplicataItem.CreVlrSdo, &CreVlrJur, &SdtPagamentoDuplicataItem.CbrMltVlr, &MoraMoeda) &SdtPagamentoDuplicataItem.CrePagVlrJur += &CreVlrJur + &MoraMoeda
&SdtPagamentoDuplicataItem.CreVlrPgt = &SdtPagamentoDuplicataItem.CreVlrSdo + &SdtPagamentoDuplicataItem.CrePagVlrJur EndFor Else For &SdtPagamentoDuplicataItem in &SdtPagamentoDuplicata &SdtPagamentoDuplicataItem.CrePagVlrJur = 0 &SdtPagamentoDuplicataItem.CreVlrPgt = &SdtPagamentoDuplicataItem.CreVlrSdo EndFor EndIf
do 'GravaSelecionadas' Refresh
EndEvent
Event &ActionSelecione.Click
if &CreDupSel = true &ActionSelecione.FromImage(DDOMultiselOption) &CreDupSel = false Else &ActionSelecione.FromImage(DDOMultiselSelOption) &CreDupSel = true Endif
If CreSts <> Status_Duplicata.CANCELADA If &CreDupSel = True
&CreVlrPgt = CreVlrSdo If &IsMostrarJuros = true CalculaJuros.Call(EmpCod,CreCbrJurCod,CreDtaVct,&CrePagDta, CreVlrSdo,&CreVlrJur, CbrMltVlr, &MoraMoeda) &CreVlrJur += &MoraMoeda If &CreVlrJur <> 0 &CreVlrPgt += &CreVlrJur EndIF Endif
&mensagem = '' If CreSts = Status_Duplicata.DESCONTADA // CreSts = 'D' = Descontadas &mensagem += 'DUPLICATAS DESCONTADAS/NEGOCIADAS, NÃO VÃO GERAR CRÉDITOS NO CAIXA!' + NewLine() Endif
&SdtPagamentoDuplicataItem = new() &SdtPagamentoDuplicataItem.EmPCod = EmpCod &SdtPagamentoDuplicataItem.FilCod = FilCod &SdtPagamentoDuplicataItem.CreCod = CreCod
&SdtPagamentoDuplicataItem.CreCheCod = CreCheCod &SdtPagamentoDuplicataItem.CreCliCod = CreCliCod &SdtPagamentoDuplicataItem.CreCliRaz = CreCliRaz &SdtPagamentoDuplicataItem.CreCliCodRaz = Trim(str(CreCliCod))+'-'+trim(CreCliRaz)
&SdtPagamentoDuplicataItem.CreVlrPgt = &CreVlrPgt &SdtPagamentoDuplicataItem.CrePagVlrJur = &CreVlrJur
&SdtPagamentoDuplicataItem.JurCod = CreCbrJurCod &SdtPagamentoDuplicataItem.CbrMltVlr = CbrMltVlr &SdtPagamentoDuplicataItem.CreDtaVct = CreDtaVct
&SdtPagamentoDuplicataItem.CreVlrSdo = CreVlrSdo
&SdtPagamentoDuplicataItem.CreCbrCod = CreCbrCod &SdtPagamentoDuplicataItem.CrePedCod = CrePedCod &SdtPagamentoDuplicataItem.CreDupNro = CreDupNro &SdtPagamentoDuplicataItem.CreDtaEms = CreDtaEms &SdtPagamentoDuplicataItem.CrePagDta = &CrePagDta &SdtPagamentoDuplicataItem.CreEnvSpc = CreEnvSpc &sdtPagamentoDuplicataItem.MovCpl = trim(str(CreCliCod)) + ' - ' + trim(CreCliRaz) &SdtPagamentoDuplicataItem.CreSts = CreSts &SdtPagamentoDuplicataItem.CrePlanCod = CrePlanCod
RetornaPlanCodNomVir.Call(EmpCod, CrePlanCod, &PLanCodNomVir) &SdtPagamentoDuplicataItem.CrePlanCodNomVir = &PLanCodNomVir
&sdtPagamentoDuplicataItem.UtilizaDataVcto = Status_SimNao.Nao &sdtPagamentoDuplicataItem.MovCtaBanCod = 0 &sdtPagamentoDuplicataItem.MovDtaCon = &DataVazia &sdtPagamentoDuplicataItem.CreFilPgt = CreFilPgt
// VALIDA SERASA If Not CreEnvSpc.IsEmpty() &mensagem += 'ATENÇÃO! Cliente:'+ Substr(trim(CreCliRaz), 1, 30) + ' Esta no SPC por esta empresa!' + NewLine() EndIf
&SdtPagamentoDuplicataItem.Mensagem = &mensagem
&CreTipBxa = TipoDuplicataBaixa.Total If &CreTipBxa = TipoDuplicataBaixa.Total and &CrevlrPgt < CreVlrSdo &SdtPagamentoDuplicataItem.CrePagVlrDsc = CreVlrSdo-&CrevlrPgt EndIf &SdtPagamentoDuplicataItem.CreTipBxa = &CreTipBxa
&SdtPagamentoDuplicata.Add(&SdtPagamentoDuplicataItem) else For &SdtPagamentoDuplicataItem in &SdtPagamentoDuplicata If &SdtPagamentoDuplicataItem.CreCod = CreCod &Index = &SdtPagamentoDuplicata.IndexOf(&SdtPagamentoDuplicataItem) &SdtPagamentoDuplicata.Remove(&Index) Exit EndIF EndFor
&CreTipBxa = TipoDuplicataBaixa.Total &CreVlrPgt = 0 &CreVlrJur = 0 Endif Else Msg('ATENÇÃO! Esta Duplicata está Cancelada e não pode ser selecionada. Verifique! ') EndIf
do 'GravaSelecionadas' &OldCreTipBxa = &CreTipBxa &OldCreVlrJur = &CreVlrJur &OldCreVlrPgt = &CreVlrPgt
EndEvent
Sub 'MarcaDesmarca'
For Each order EmpCod, CreCliCod, CreDtaVct using DSwwDuplicataReceber2(&CreCliCod, &CreCliCodRazSugg,&CreFilPgt, &CreDtaVct, &CreDtaVct_To, &CreRecPag, &CreSts, &CreVlrSdo, &CreFrpPgtoTip, &DynamicFiltersSelector1, &CreDupNro1, &CreCbrNom1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &CreDupNro2, &CreCbrNom2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &CreDupNro3, &CreCbrNom3) //defined by CreDupNro
If CreSts <> Status_Duplicata.CANCELADA &CreDupSel = true &CreVlrPgt = CreVlrSdo
If &IsMostrarJuros = true CalculaJuros.Call(EmpCod,CreCbrJurCod,CreDtaVct,&CrePagDta, CreVlrSdo,&CreVlrJur, CbrMltVlr, &MoraMoeda) &CreVlrJur += &MoraMoeda If &CreVlrJur <> 0 &CreVlrPgt += &CreVlrJur EndIF Endif
&CreTipBxa = TipoDuplicataBaixa.Total
&mensagem = '' If CreSts = Status_Duplicata.DESCONTADA // CreSts = 'D' = Descontadas &mensagem += 'DUPLICATAS DESCONTADAS/NEGOCIADAS, NÃO VÃO GERAR CRÉDITOS NO CAIXA!' + NewLine() Endif
&IsAchou = false
For &SdtPagamentoDuplicataItem in &SdtPagamentoDuplicata If &SdtPagamentoDuplicataItem.CreCod = CreCod and &SdtPagamentoDuplicataItem.FilCod = FilCod &IsAchou = true EndIf EndFor
If &IsAchou = false &SdtPagamentoDuplicataItem = new() &SdtPagamentoDuplicataItem.EmPCod = EmpCod &SdtPagamentoDuplicataItem.FilCod = FilCod &SdtPagamentoDuplicataItem.CreCod = CreCod &SdtPagamentoDuplicataItem.CreCheCod = CreCheCod
&SdtPagamentoDuplicataItem.CreCliCod = CreCliCod &SdtPagamentoDuplicataItem.CreCliRaz = CreCliRaz &SdtPagamentoDuplicataItem.CreCliCodRaz = Trim(str(CreCliCod))+'-'+trim(CreCliRaz)
&SdtPagamentoDuplicataItem.CreVlrPgt = &CreVlrPgt &SdtPagamentoDuplicataItem.CrePagVlrJur = &CreVlrJur
&SdtPagamentoDuplicataItem.JurCod = CreCbrJurCod &SdtPagamentoDuplicataItem.CbrMltVlr = CbrMltVlr &SdtPagamentoDuplicataItem.CreDtaVct = CreDtaVct
&SdtPagamentoDuplicataItem.CreVlrSdo = CreVlrSdo &SdtPagamentoDuplicataItem.CreCbrCod = CreCbrCod &SdtPagamentoDuplicataItem.CrePedCod = CrePedCod &SdtPagamentoDuplicataItem.CreDupNro = CreDupNro &SdtPagamentoDuplicataItem.CreDtaEms = CreDtaEms &SdtPagamentoDuplicataItem.CrePagDta = &CrePagDta &SdtPagamentoDuplicataItem.CreEnvSpc = CreEnvSpc &sdtPagamentoDuplicataItem.MovCpl = trim(str(CreCliCod)) + ' - ' + trim(CreCliRaz) &SdtPagamentoDuplicataItem.CreSts = CreSts &SdtPagamentoDuplicataItem.CrePlanCod = CrePlanCod
RetornaPlanCodNomVir.Call(EmpCod, CrePlanCod, &PLanCodNomVir) &SdtPagamentoDuplicataItem.CrePlanCodNomVir = &PLanCodNomVir
&sdtPagamentoDuplicataItem.UtilizaDataVcto = Status_SimNao.Nao &sdtPagamentoDuplicataItem.MovCtaBanCod = 0 &sdtPagamentoDuplicataItem.MovDtaCon = &DataVazia &sdtPagamentoDuplicataItem.CreFilPgt = CreFilPgt
// VALIDA SERASA If Not CreEnvSpc.IsEmpty() &mensagem += 'ATENÇÃO! Cliente:'+ Substr(trim(CreCliRaz), 1, 30) + ' Esta no SPC por esta empresa!' + NewLine() EndIf
&SdtPagamentoDuplicataItem.Mensagem = &mensagem
// VALIDA TIPO BAIXA &CreTipBxa = TipoDuplicataBaixa.Total If &CreTipBxa = TipoDuplicataBaixa.Total and &CrevlrPgt < CreVlrSdo &SdtPagamentoDuplicataItem.CrePagVlrDsc = CreVlrSdo-&CrevlrPgt EndIf &SdtPagamentoDuplicataItem.CreTipBxa = &CreTipBxa
&SdtPagamentoDuplicata.Add(&SdtPagamentoDuplicataItem) EndIF Else Msg('ATENÇÃO! Esta Duplicata está Cancelada e não pode ser selecionada. Verifique! ') EndIf EndFor
EndSub
Sub 'loadSelecionados'
padraoUsuario.Call('L', 'SEL_WWDuplicataReceber2', &Context.PesCod, &Context.EmpCod, &PadObs, &PadDtaMod) &SdtpagamentoDuplicata.FromJson(&PadObs) &numeric = &SdtpagamentoDuplicata.Count DuplicatasSelect.Caption = trim(str(&numeric)) + ' - Duplicatas Selec.'
do 'Totaliza'
EndSub
Sub 'IsSelecionado'
For &SdtpagamentoDuplicataItem in &SdtpagamentoDuplicata If &SdtpagamentoDuplicataItem.CreCod = &AuxCreCod &CreDupSel = true &CreVlrPgt = &SdtpagamentoDuplicataItem.CreVlrPgt &CreVlrJur = &SdtpagamentoDuplicataItem.CrePagVlrJur &CreTipBxa = &SdtpagamentoDuplicataItem.CreTipBxa exit EndIf EndFor
EndSub
Sub 'GravaSelecionadas'
&numeric = &SdtPagamentoDuplicata.Count DuplicatasSelect.Caption = trim(str(&numeric)) + ' - Duplicatas Selec.'
padraoUsuario.Call('G', 'SEL_WWDuplicataReceber2', &Context.PesCod, &Context.EmpCod, &SdtPagamentoDuplicata.ToJson(), &PadDtaMod)
do 'Totaliza'
EndSub
Sub 'Totaliza'
&TotNaoDescontada = 0 &TotDescontada = 0 &TotCreVlrSdo = 0 For &SdtpagamentoDuplicataItem in &SdtpagamentoDuplicata &TotCreVlrSdo += &SdtPagamentoDuplicataItem.CreVlrPgt
If &SdtPagamentoDuplicataItem.CreSts = Status_Duplicata.DESCONTADA //DESCONTADA &TotDescontada += 1 Else &TotNaoDescontada += 1 EndIF
EndFor
EndSub
Sub 'GravaPadrao'
&PadObs = DTOC(&CrePagDta)
if &IsMostrarTodos = true &PadObs += '0' Else &PadObs += '1' Endif
padraoUsuario.Call('G', 'WWDuplicataReceber2', &Context.PesCod, &Context.EmpCod, &PadObs, &PadDtaMod)
EndSub
